import{_ as t,c as l,o,a5 as i,j as e}from"./chunks/framework.Dtwt352Q.js";const g=JSON.parse('{"title":"v1.1.37: File Tree Mode, Highlight Feature, Thai Language Support","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.37.md","filePath":"en/changelog/v1.1.37.md","lastUpdated":1772014034000}'),n={name:"en/changelog/v1.1.37.md"};function r(s,a,d,p,h,c){return o(),l("div",null,[...a[0]||(a[0]=[i('<h1 id="v1-1-37-file-tree-mode-highlight-feature-thai-language-support" tabindex="-1">v1.1.37: File Tree Mode, Highlight Feature, Thai Language Support <a class="header-anchor" href="#v1-1-37-file-tree-mode-highlight-feature-thai-language-support" aria-label="Permalink to “v1.1.37: File Tree Mode, Highlight Feature, Thai Language Support”">​</a></h1><p><strong>Release Date</strong>: January 28, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update adds file tree mode, code highlighting feature, Thai language support, and brings many interface and performance improvements.</p><hr><h2 id="new-feature-file-tree-mode" tabindex="-1">New Feature: File Tree Mode <a class="header-anchor" href="#new-feature-file-tree-mode" aria-label="Permalink to “New Feature: File Tree Mode”">​</a></h2><h3 id="what-was-updated" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added file tree view mode for more intuitive browsing and management of project file structure.</p><h3 id="what-is-file-tree-mode" tabindex="-1">What is File Tree Mode? <a class="header-anchor" href="#what-is-file-tree-mode" aria-label="Permalink to “What is File Tree Mode?”">​</a></h3><p>File tree mode displays project files and directories in a tree structure, similar to the VS Code file browser you&#39;re familiar with, for quick navigation and file location.</p><h3 id="how-to-use" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to use?”">​</a></h3><p>In the Desktop app:</p><ol><li>Open project</li><li>Click the file tree icon in the sidebar</li><li>Browse and expand folders, click files to open</li><li>Use arrow keys to navigate</li><li>Type keywords to quickly filter files</li></ol><hr><h2 id="new-feature-code-highlighting" tabindex="-1">New Feature: Code Highlighting <a class="header-anchor" href="#new-feature-code-highlighting" aria-label="Permalink to “New Feature: Code Highlighting”">​</a></h2><h3 id="what-was-updated-1" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-1" aria-label="Permalink to “What was updated?”">​</a></h3><p>In the file tree, modified files are marked with different colors, and dots indicate change types (added, modified, deleted).</p><h3 id="how-to-use-1" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to use?”">​</a></h3><p>When viewing the file tree:</p><ul><li>🔴 Red dot: Deleted file</li><li>🟡 Yellow dot: Modified file</li><li>🟢 Green dot: New file</li><li>No dot: Unchanged file</li></ul><hr><h2 id="new-feature-headless-authentication-support" tabindex="-1">New Feature: Headless Authentication Support <a class="header-anchor" href="#new-feature-headless-authentication-support" aria-label="Permalink to “New Feature: Headless Authentication Support”">​</a></h2><h3 id="what-was-updated-2" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-2" aria-label="Permalink to “What was updated?”">​</a></h3><p>Now supports headless authentication for ChatGPT and Codex, better suited for automation scenarios.</p><h3 id="what-is-headless-authentication" tabindex="-1">What is Headless Authentication? <a class="header-anchor" href="#what-is-headless-authentication" aria-label="Permalink to “What is Headless Authentication?”">​</a></h3><p>Headless authentication is an authentication method that doesn&#39;t require browser interaction, suitable for CI/CD, scripts, and other automation scenarios.</p><h3 id="how-to-use-2" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use-2" aria-label="Permalink to “How to use?”">​</a></h3><p>When configuring ChatGPT or Codex providers, use environment variables or configuration files to set API keys without manual browser authorization.</p><hr><h2 id="new-feature-more-language-support" tabindex="-1">New Feature: More Language Support <a class="header-anchor" href="#new-feature-more-language-support" aria-label="Permalink to “New Feature: More Language Support”">​</a></h2><h3 id="what-was-updated-3" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-3" aria-label="Permalink to “What was updated?”">​</a></h3><ul><li>Added Thai language support</li><li>Improved Chinese localization experience</li></ul><hr><h2 id="new-feature-learn-command" tabindex="-1">New Feature: Learn Command <a class="header-anchor" href="#new-feature-learn-command" aria-label="Permalink to “New Feature: Learn Command”">​</a></h2><h3 id="what-was-updated-4" tabindex="-1">What was updated? <a class="header-anchor" href="#what-was-updated-4" aria-label="Permalink to “What was updated?”">​</a></h3><p>Added <code>/learn</code> command to extract learning points from sessions and save to AGENTS.md file.</p><h3 id="how-to-use-3" tabindex="-1">How to use? <a class="header-anchor" href="#how-to-use-3" aria-label="Permalink to “How to use?”">​</a></h3><p>In a session, type:</p>',39),e("div",{class:"language-"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"}),e("pre",null,[e("code",{"v-pre":""},"/learn")])],-1),i('<p>OpenCode will automatically analyze session content, extract key learning points, and save to the project&#39;s AGENTS.md file.</p><hr><h2 id="bug-fix-session-sync-issue" tabindex="-1">Bug Fix: Session Sync Issue <a class="header-anchor" href="#bug-fix-session-sync-issue" aria-label="Permalink to “Bug Fix: Session Sync Issue”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>In some cases, session sync would have problems, causing inconsistent state.</p><h3 id="current-status" tabindex="-1">Current Status <a class="header-anchor" href="#current-status" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed the session sync mechanism to ensure state is always consistent.</p><hr><h2 id="bug-fix-terminal-corruption" tabindex="-1">Bug Fix: Terminal Corruption <a class="header-anchor" href="#bug-fix-terminal-corruption" aria-label="Permalink to “Bug Fix: Terminal Corruption”">​</a></h2><h3 id="previous-issue-1" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue-1" aria-label="Permalink to “Previous Issue”">​</a></h3><p>The terminal in Desktop app might have display corruption or become unresponsive.</p><h3 id="current-status-1" tabindex="-1">Current Status <a class="header-anchor" href="#current-status-1" aria-label="Permalink to “Current Status”">​</a></h3><p>Fixed terminal-related rendering issues to ensure the terminal always works properly.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using Desktop version</td><td>✅ Highly recommended (many improvements)</td></tr><tr><td>Need better file browsing experience</td><td>✅ Highly recommended</td></tr><tr><td>Using automation scripts</td><td>✅ Recommended upgrade</td></tr><tr><td>Everything working fine</td><td>Can wait for next time</td></tr></tbody></table><p><strong>Upgrade command</strong>:</p>',17),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),i('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full update list</summary><h3 id="core" tabindex="-1">Core <a class="header-anchor" href="#core" aria-label="Permalink to “Core”">​</a></h3><ul><li>Support headless authentication for ChatGPT/Codex (@rgodha24)</li><li>Add recommended topP and temperature settings for Kimi K2.5 model</li><li>Adjust retry check to be more defensive</li><li>Handle Venice cache creation tokens (@dpuyosa)</li><li>Add worktree to plugin tool context</li><li>Expose Instance.directory to custom tools</li><li>Use Instance.directory instead of process.cwd() in read tool</li><li>Fix reactive file tree to properly update when files change</li><li>Attach Anthropic beta headers when using Messages API for Copilot</li><li>Add retry logic to handle certain provider problems</li><li>Ensure OpenAI 404 errors are retried (@tim-smart)</li><li>Use Anthropic-compatible messages API for Anthropic models through Copilot</li><li>Upgrade OpenTUI to v0.1.75</li><li>Dynamically resolve AGENTS.md files from subdirectories as agent explores them</li><li>Add agent description to OpenCode (@SteffenDE)</li><li>Fix query selector handling of non-Latin characters</li><li>Await SessionRevert.cleanup for shell to prevent race conditions (@noamzbr)</li><li>Don&#39;t override source in custom provider loaders</li><li>Add provider settings to app</li><li>Run start command after reset in app</li><li>Remove log statement</li></ul><h3 id="tui" tabindex="-1">TUI <a class="header-anchor" href="#tui" aria-label="Permalink to “TUI”">​</a></h3><ul><li>Handle 4-5 digit codes in copy logic</li><li>Make diff wrapping toggle always available in command list and fix type error (@ariane-emory)</li><li>Add visual feedback for diff wrap and conceal toggles (@IdrisGit)</li><li>Adjust TUI syncing logic to prevent agents from being undefined or missing</li><li>Remove broken app.tsx command option</li><li>Move animations toggle to global System category (@ariane-emory)</li></ul><h3 id="desktop" tabindex="-1">Desktop <a class="header-anchor" href="#desktop" aria-label="Permalink to “Desktop”">​</a></h3><ul><li>Reintroduce review tab in app</li><li>Auto-scroll to keep relevant content in view</li><li>Add &#39;connect provider&#39; button to the manage models dialog (@alexyaroshuk)</li><li>Fix terminal corruption issue in app</li><li>File tree not always loading in app</li><li>Fix outdated e2e test in app package</li><li>Do not auto-navigate to last project on app load</li><li>Add Tauri localization support to desktop application</li><li>Add internationalization support for Tauri desktop application</li><li>Better memory management in app</li><li>Don&#39;t connect to localhost through VPN</li><li>Show 5 highlights in app</li><li>Highlight selected change in the app</li><li>Set filetree padding to 6px</li><li>Align file tree change styling</li><li>Delay navigation tooltips</li><li>Adjust titlebar left spacing</li><li>Shorten navigation tooltips</li><li>Add filetree tooltips with diff labels</li><li>Color file tree change dots by diff kind</li><li>Improved app layout</li><li>Fix session diffs not always loading in app</li><li>New end-to-end smoke tests for app</li><li>Add translations to the app</li><li>Update settings in general settings</li><li>Swallow file search errors in app</li><li>Fix tooltips causing getComputedStyle errors in model select</li><li>Clean up Tailwind CSS versus pure CSS usage in app</li><li>Navigate to tabs when opening file in app</li><li>Open markdown links in external browser</li><li>Shared terminal ghostty-web instance for better performance</li><li>Cleanup connect provider timers</li><li>Don&#39;t keep parts in memory</li><li>Don&#39;t show session skeleton after workspace reset</li><li>Add max-width to tabs with text truncation</li><li>Use smaller close icon on tabs to match comment cards</li><li>Only show left border on plus button when sticky</li><li>Update review empty states to 14px font size and align select file empty state</li><li>Center file tree empty state with 32px top margin</li><li>Implement non-fatal error handling in app</li><li>Fix agent fallback colors in app</li><li>Added forward and back navigation buttons</li><li>Add missing tooltips in app</li><li>Auto-scroll button sometimes sticks in the app</li><li>Deduplicate Tauri configuration files (@Brendonovich)</li><li>Only show files in select dialog when clicking + tab</li><li>Disable magnification gestures on macOS desktop (@ysm-dev)</li><li>Add Connect provider in model selector (@ProdigyRahul)</li><li>Add file tree specification tests</li><li>Enable file watcher in app</li><li>Improve file tree performance in app</li><li>Add highlights feature</li><li>Add new release modal</li><li>Fix Zen mode disconnect not working in app</li><li>Disconnect Zen provider</li><li>Fix e2e test in app package</li><li>Disable tooltips in file tree tabs</li><li>Move file tree toggle button to the right side</li><li>Fade filetree guide lines on hover</li><li>Dim non-deep filetree guide lines in the app interface</li><li>Reduce file tree folder indent</li><li>Refine file tree row spacing and indentation</li><li>Use medium font weight for filetree items</li><li>Use chevron icons for filetree folders</li><li>Tighten file tree row spacing</li><li>Adjust filetree panel padding</li><li>Scope filetree pill tabs styling</li><li>Add Vercel AI Gateway provider description</li><li>Add provider descriptions to settings</li><li>Add transition to command palette</li><li>Add transition to select provider dialog</li><li>Add optional transition animations to dialog</li><li>Style view all button with interactive color and margin</li><li>Add models icon and use in settings UI</li><li>Add providers icon and use in settings</li><li>Use default cursor for environment provider text</li><li>Add hover text for environment-connected providers</li><li>Set provider row height to 56px</li><li>Update button styles and disconnect button size in UI</li><li>Fix session synchronization issue in application</li><li>Add missing i18n strings in app</li><li>Add session load limit to prevent excessive memory usage</li><li>Add end-to-end test for sidebar navigation</li><li>Replace signals with createStore in app</li><li>Add file tree mode to app</li><li>Add file tree view to app</li><li>Use focus-visible instead of focus to prevent sticky hover effect on click (@ProdigyRahul)</li><li>Better sidebar hover behavior when collapsed</li><li>Make sidebar full-height in app</li><li>Add full-height hover effect to sidebar</li><li>Add model settings to application</li><li>Add model settings interface to app</li><li>Handle non-tool call permissions in app</li><li>Default servers on web</li><li>Performance improvements in the app</li><li>Add missing translations for status messages</li><li>Don&#39;t allow workspaces in non-VCS projects</li></ul><p><strong>Thank you to 17 community contributors:</strong></p><p>@MartinWie:</p><ul><li>docs: fix permission event name (permission.asked not permission.updated) (#10588)</li></ul><p>@ariane-emory:</p><ul><li>fix(tui): Move animations toggle to global System category (resolves #10495) (#10497)</li><li>fix: Make diff wrapping toggle always available in command_list and correct a type error (resolves #10682) (#10683)</li></ul><p>@R44VC0RP:</p><ul><li>Add highlight tag parsing for changelog with video support</li><li>Add collapsible sections, sticky version header, and style refinements for changelog highlights</li><li>fix(web): update spacing on the changelog page</li><li>docs: add warning about Claude Pro/Max subscription support (#10595)</li><li>fix: move changelog footer outside content div to fix padding (#10712)</li><li>fix: add 44px top padding to sticky version header on changelog (#10715)</li><li>feat(release): add highlights template to draft releases (#10745)</li><li>feat: add /learn command to extract session learnings to scoped AGENTS.md files (#10717)</li></ul><p>@IdrisGit:</p><ul><li>fix(tui): add visual feedback for diff wrap and conceal toggles (#10655)</li></ul><p>@noamzbr:</p><ul><li>fix: await SessionRevert.cleanup for shell (#10669)</li></ul><p>@SteffenDE:</p><ul><li>feat(opencode): add agent description (#10680)</li></ul><p>@sam-huckaby:</p><ul><li>fix(app): Order themes alphabetically (#10698)</li></ul><p>@alexyaroshuk:</p><ul><li>fix(app): restore external link opening in system browser (#10697)</li><li>feat(app): add &#39;connect provider&#39; button to the manage models dialog (#10887)</li></ul><p>@ProdigyRahul:</p><ul><li>fix(ui): use focus-visible instead of focus to prevent sticky hover effect on click (#10651)</li><li>fix(app): add connect provier in model selector (#10706)</li></ul><p>@zerone0x:</p><ul><li>fix(enterprise): add message navigation to share page desktop view (#10071)</li></ul><p>@tim-smart:</p><ul><li>fix: ensure openai 404 errors are retried (#10590)</li></ul><p>@fabiomartino:</p><ul><li>docs: add Italian README (#10732)</li></ul><p>@ysm-dev:</p><ul><li>fix(desktop): disable magnification gestures on macOS (#10605)</li></ul><p>@Brendonovich:</p><ul><li>desktop: deduplicate tauri configs</li></ul><p>@dpuyosa:</p><ul><li>feat(opencode): Handle Venice cache creation tokens (#10735)</li></ul><p>@OpeOginni:</p><ul><li>chore(docs): Better explanation on how to allow tools in external directories (#10862)</li></ul><p>@rgodha24:</p><ul><li>feat: support headless authentication for chatgpt/codex (#10890)</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const m=t(n,[["render",r]]);export{g as __pageData,m as default};
